import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Home = () => {
    const [artisans, setArtisans] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/artisans/top')
            .then(res => setArtisans(res.data))
            .catch(err => console.error("Erreur artisans:", err));
    }, []);

    const renderStars = (note) => {
        const stars = [];
        for (let i = 1; i <= 5; i++) {
            stars.push(
                <span key={i} style={{ color: i <= note ? '#ffc107' : '#e4e5e9' }}>★</span>
            );
        }
        return stars;
    };

    return (
        <div className="container py-5">
            <section className="mb-5">
                <h2 className="fw-bold mb-4" style={{ color: '#004a99' }}>Comment trouver mon artisan ?</h2>
                <div className="row g-4">
                    <div className="col-md-3">
                        <div className="d-flex align-items-center mb-2">
                            <span className="badge rounded-circle bg-primary me-2">1</span>
                            <span className="fw-bold">Choisir la catégorie d’artisanat dans le menu.</span>
                        </div>
                    </div>
                    <div className="col-md-3">
                        <div className="d-flex align-items-center mb-2">
                            <span className="badge rounded-circle bg-primary me-2">2</span>
                            <span className="fw-bold">Choisir un artisan.</span>
                        </div>
                    </div>
                    <div className="col-md-3">
                        <div className="d-flex align-items-center mb-2">
                            <span className="badge rounded-circle bg-primary me-2">3</span>
                            <span className="fw-bold">Le contacter via le formulaire de contact.</span>
                        </div>
                    </div>
                    <div className="col-md-3">
                        <div className="d-flex align-items-center mb-2">
                            <span className="badge rounded-circle bg-primary me-2">4</span>
                            <span className="fw-bold">Une réponse sera apportée sous 48h.</span>
                        </div>
                    </div>
                </div>
            </section>

            <hr className="my-5" />

            <h2 className="text-center mb-5 fw-bold" style={{ color: '#004a99' }}>
                Artisans du mois
            </h2>

            <div className="row g-4">
                {artisans.length > 0 ? (
                    artisans.map(artisan => (
                        <div className="col-12 col-md-4" key={artisan.id}>
                            <div className="card h-100 border-0 shadow-sm text-center p-3">
                                <div className="card-body">
                                    <h5 className="card-title fw-bold">{artisan.name || artisan.nom}</h5>
                                    <div className="mb-2">
                                        {renderStars(artisan.note)}
                                        <small className="ms-2 text-muted">({artisan.note}/5)</small>
                                    </div>
                                    <p className="card-text text-secondary small">
                                        <strong>Spécialité :</strong> {artisan.specialite || "Artisan"}<br/>
                                        <strong>Localisation :</strong> {artisan.location || artisan.lieu}
                                    </p>
                                    <button className="btn btn-primary rounded-pill px-4 mt-3" style={{ backgroundColor: '#0082c3', border: 'none' }}>
                                        Voir le profil
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <p className="text-center">Chargement des artisans du mois...</p>
                )}
            </div>
        </div>
    );
};

export default Home;
